hero.css:
/* =============================================
   HERO_001 — Kavya & Mihir | Royal Gujarati
   ============================================= */

/* --- Root shell --- */
.hero_001 {
  position: relative;
  min-height: 100vh;
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  padding: 0 0 64px 0;
  box-sizing: border-box;
  font-family: 'Manrope', sans-serif;
}

/* --- Background base gradient --- */
.hero_001__bg-base {
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 20% 10%, #3b0a1f 0%, transparent 55%),
    radial-gradient(ellipse 70% 50% at 80% 90%, #1a0a30 0%, transparent 55%),
    linear-gradient(160deg, #1c0a28 0%, #2e0d1a 30%, #1a0c22 60%, #0e0818 100%);
  z-index: 0;
}

/* --- Subtle brocade pattern overlay --- */
.hero_001__bg-pattern {
  position: absolute;
  inset: 0;
  z-index: 1;
  opacity: 0.07;
  background-image:
    repeating-linear-gradient(
      45deg,
      #c9a84c 0px, #c9a84c 1px,
      transparent 1px, transparent 28px
    ),
    repeating-linear-gradient(
      -45deg,
      #c9a84c 0px, #c9a84c 1px,
      transparent 1px, transparent 28px
    );
}

/* --- Vignette --- */
.hero_001__bg-vignette {
  position: absolute;
  inset: 0;
  z-index: 2;
  background: radial-gradient(ellipse 85% 85% at 50% 50%, transparent 40%, rgba(8,4,16,0.72) 100%);
}

/* --- Floating orbs --- */
.hero_001__orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(72px);
  z-index: 1;
  pointer-events: none;
}
.hero_001__orb--tl {
  width: 420px;
  height: 420px;
  top: -120px;
  left: -120px;
  background: radial-gradient(circle, rgba(180,80,30,0.35) 0%, transparent 70%);
  animation: hero001OrbPulse 8s ease-in-out infinite alternate;
}
.hero_001__orb--br {
  width: 500px;
  height: 500px;
  bottom: -160px;
  right: -140px;
  background: radial-gradient(circle, rgba(100,20,120,0.4) 0%, transparent 70%);
  animation: hero001OrbPulse 10s ease-in-out infinite alternate-reverse;
}
.hero_001__orb--tr {
  width: 300px;
  height: 300px;
  top: 10%;
  right: 5%;
  background: radial-gradient(circle, rgba(201,168,76,0.18) 0%, transparent 70%);
  animation: hero001OrbPulse 12s ease-in-out infinite alternate;
}

@keyframes hero001OrbPulse {
  0%   { transform: scale(1) translateY(0px); }
  100% { transform: scale(1.12) translateY(-20px); }
}

/* --- Toran strip --- */
.hero_001__toran-strip {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 38px;
  display: flex;
  align-items: flex-start;
  justify-content: space-around;
  z-index: 10;
  background: linear-gradient(90deg, #7b1c2e, #a8362a, #c9a84c, #a8362a, #7b1c2e);
  padding: 0 12px;
  box-shadow: 0 3px 18px rgba(201,168,76,0.25);
}
.hero_001__toran-leaf {
  width: 28px;
  height: 44px;
  border-radius: 0 0 50% 50%;
  background: linear-gradient(180deg, #2e8b3a 0%, #4caf50 50%, #81c784 100%);
  box-shadow: inset 0 -4px 8px rgba(0,0,0,0.25), 0 2px 8px rgba(0,0,0,0.2);
  position: relative;
  top: 0;
  flex-shrink: 0;
}
.hero_001__toran-leaf::after {
  content: '';
  position: absolute;
  bottom: 4px;
  left: 50%;
  transform: translateX(-50%);
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #f5c842;
  box-shadow: 0 0 6px rgba(245,200,66,0.8);
}

/* --- Corner ornaments --- */
.hero_001__corner {
  position: absolute;
  z-index: 5;
  pointer-events: none;
}
.hero_001__corner--tl {
  top: 36px;
  left: 0;
  width: 160px;
  height: 160px;
}
.hero_001__corner--br {
  bottom: 60px;
  right: 0;
  width: 160px;
  height: 160px;
}

/* --- Diya floating elements --- */
.hero_001__diya {
  position: absolute;
  z-index: 6;
  width: 54px;
  height: 72px;
  filter: drop-shadow(0 0 14px rgba(255,180,0,0.55));
  animation: hero001DiyaFlicker 3s ease-in-out infinite alternate;
}
.hero_001__diya--left {
  left: 5%;
  bottom: 18%;
}
.hero_001__diya--right {
  right: 5%;
  bottom: 22%;
  animation-delay: 1.5s;
}

@keyframes hero001DiyaFlicker {
  0%   { filter: drop-shadow(0 0 10px rgba(255,160,0,0.5)) brightness(1); }
  50%  { filter: drop-shadow(0 0 22px rgba(255,200,0,0.9)) brightness(1.15); }
  100% { filter: drop-shadow(0 0 14px rgba(255,140,0,0.6)) brightness(1.05); }
}

/* --- Glass wrap --- */
.hero_001__glass-wrap {
  position: relative;
  z-index: 20;
  width: 100%;
  max-width: 820px;
  padding: 56px 24px 24px;
  margin-top: 38px;
  box-sizing: border-box;
}

/* --- Glass panel --- */
.hero_001__glass-panel {
  background: linear-gradient(145deg, rgba(255,255,255,0.06) 0%, rgba(201,168,76,0.06) 50%, rgba(120,20,60,0.08) 100%);
  border: 1px solid rgba(201,168,76,0.28);
  border-radius: 24px;
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  box-shadow:
    0 0 0 1px rgba(255,255,255,0.04) inset,
    0 32px 80px rgba(0,0,0,0.55),
    0 0 60px rgba(201,168,76,0.08);
  padding: 52px 60px 48px;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  box-sizing: border-box;
}

/* --- Badge (Ganesh invocation) --- */
.hero_001__badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: linear-gradient(135deg, rgba(201,168,76,0.18) 0%, rgba(201,168,76,0.08) 100%);
  border: 1px solid rgba(201,168,76,0.45);
  border-radius: 999px;
  padding: 7px 22px;
  margin-bottom: 24px;
  animation: hero001BadgeFadeIn 1.2s ease both;
}
.hero_001__badge-symbol {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 1.3rem;
  color: #f5c842;
  line-height: 1;
}
.hero_001__badge-text {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 0.82rem;
  color: #e8c97a;
  letter-spacing: 0.08em;
  font-weight: 600;
}

@keyframes hero001BadgeFadeIn {
  from { opacity: 0; transform: translateY(-12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* --- Gujarati pre-title --- */
.hero_001__guj-pre {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 0.88rem;
  color: rgba(232,201,122,0.7);
  letter-spacing: 0.04em;
  margin: 0 0 20px 0;
  animation: hero001FadeUp 1.4s ease 0.2s both;
}

/* --- Names wrap --- */
.hero_001__names-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 28px;
  margin-bottom: 28px;
  animation: hero001FadeUp 1.4s ease 0.3s both;
}

.hero_001__name {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}
.hero_001__name-label {
  font-family: 'Manrope', sans-serif;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(201,168,76,0.65);
}
.hero_001__name-text {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(3.2rem, 8vw, 5.6rem);
  font-weight: 600;
  font-style: italic;
  color: #fff;
  line-height: 1;
  letter-spacing: -0.01em;
  text-shadow:
    0 0 40px rgba(201,168,76,0.35),
    0 2px 20px rgba(0,0,0,0.5);
}

/* --- Ampersand --- */
.hero_001__ampersand-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}
.hero_001__ampersand {
  font-family: 'Rozha One', serif;
  font-size: clamp(2rem, 5vw, 3.4rem);
  color: #c9a84c;
  line-height: 1;
  text-shadow: 0 0 30px rgba(201,168,76,0.6);
  animation: hero001GoldGlow 4s ease-in-out infinite alternate;
}
.hero_001__ampersand-line {
  width: 1px;
  height: 36px;
  background: linear-gradient(180deg, transparent, rgba(201,168,76,0.5), transparent);
}

@keyframes hero001GoldGlow {
  0%   { text-shadow: 0 0 20px rgba(201,168,76,0.4); }
  100% { text-shadow: 0 0 50px rgba(245,200,66,0.85), 0 0 80px rgba(201,168,76,0.3); }
}

/* --- Gold divider --- */
.hero_001__divider {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 28px;
  animation: hero001FadeUp 1.4s ease 0.5s both;
}
.hero_001__divider-line {
  width: 80px;
  height: 1px;
  background: linear-gradient(90deg, transparent, #c9a84c, transparent);
}
.hero_001__divider-dot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: #c9a84c;
  box-shadow: 0 0 8px rgba(201,168,76,0.8);
}
.hero_001__divider-icon {
  color: #f5c842;
  font-size: 0.9rem;
  line-height: 1;
  animation: hero001SpinSlow 20s linear infinite;
  display: inline-block;
}
@keyframes hero001SpinSlow {
  to { transform: rotate(360deg); }
}

/* --- Date block --- */
.hero_001__date-block {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  margin-bottom: 22px;
  animation: hero001FadeUp 1.4s ease 0.6s both;
}
.hero_001__date-label {
  font-family: 'Manrope', sans-serif;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: rgba(201,168,76,0.6);
}
.hero_001__date-value {
  font-family: 'Playfair Display', serif;
  font-size: clamp(1.4rem, 3.5vw, 2.1rem);
  font-weight: 700;
  color: #fff;
  letter-spacing: 0.04em;
}
.hero_001__date-guj {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 0.9rem;
  color: rgba(232,201,122,0.6);
  letter-spacing: 0.06em;
}

/* --- Venue --- */
.hero_001__venue-wrap {
  display: flex;
  align-items: center;
  gap: 12px;
  background: rgba(201,168,76,0.07);
  border: 1px solid rgba(201,168,76,0.2);
  border-radius: 12px;
  padding: 12px 24px;
  margin-bottom: 28px;
  animation: hero001FadeUp 1.4s ease 0.7s both;
}
.hero_001__venue-icon {
  font-size: 1.5rem;
  line-height: 1;
  filter: drop-shadow(0 0 8px rgba(201,168,76,0.5));
}
.hero_001__venue-details {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 2px;
}
.hero_001__venue-name {
  font-family: 'Playfair Display', serif;
  font-size: 1.05rem;
  font-weight: 700;
  color: #f0dfa0;
  letter-spacing: 0.02em;
}
.hero_001__venue-location {
  font-family: 'Manrope', sans-serif;
  font-size: 0.76rem;
  font-weight: 500;
  color: rgba(220,200,160,0.65);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

/* --- Hero message --- */
.hero_001__message {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(1rem, 2.2vw, 1.2rem);
  font-style: italic;
  font-weight: 500;
  color: rgba(245,235,210,0.8);
  line-height: 1.75;
  max-width: 560px;
  margin: 0 0 28px 0;
  animation: hero001FadeUp 1.4s ease 0.8s both;
}

/* --- Events ribbon --- */
.hero_001__events-ribbon {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  justify-content: center;
  gap: 6px;
  margin-bottom: 36px;
  animation: hero001FadeUp 1.4s ease 0.9s both;
}
.hero_001__event-pill {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 0.82rem;
  font-weight: 600;
  color: #c9a84c;
  background: rgba(201,168,76,0.1);
  border: 1px solid rgba(201,168,76,0.28);
  border-radius: 999px;
  padding: 5px 16px;
  letter-spacing: 0.05em;
  transition: background 0.3s ease, color 0.3s ease;
}
.hero_001__event-pill:hover {
  background: rgba(201,168,76,0.22);
  color: #f5c842;
}
.hero_001__event-sep {
  color: rgba(201,168,76,0.35);
  font-size: 1rem;
}

/* --- CTA button --- */
.hero_001__cta {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  background: linear-gradient(135deg, #c9a84c 0%, #e8c97a 50%, #b8892a 100%);
  color: #1a0c22;
  font-family: 'Manrope', sans-serif;
  font-size: 0.82rem;
  font-weight: 800;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  text-decoration: none;
  padding: 16px 40px;
  border-radius: 999px;
  box-shadow:
    0 0 0 1px rgba(245,200,66,0.3),
    0 8px 32px rgba(201,168,76,0.4),
    0 2px 8px rgba(0,0,0,0.3);
  transition: transform 0.25s ease, box-shadow 0.25s ease, filter 0.25s ease;
  animation: hero001FadeUp 1.4s ease 1.1s both;
  position: relative;
  overflow: hidden;
}
.hero_001__cta::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(255,255,255,0.18) 0%, transparent 60%);
  border-radius: inherit;
}
.hero_001__cta:hover {
  transform: translateY(-3px) scale(1.03);
  box-shadow:
    0 0 0 2px rgba(245,200,66,0.5),
    0 16px 48px rgba(201,168,76,0.55),
    0 4px 16px rgba(0,0,0,0.35);
  filter: brightness(1.08);
}
.hero_001__cta-text {
  position: relative;
  z-index: 1;
}
.hero_001__cta-icon {
  position: relative;
  z-index: 1;
  font-size: 1rem;
  transition: transform 0.25s ease;
}
.hero_001__cta:hover .hero_001__cta-icon {
  transform: translateX(4px);
}

/* --- Marigold bottom band --- */
.hero_001__marigold-band {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 54px;
  display: flex;
  align-items: center;
  justify-content: space-around;
  padding: 0 8px;
  background: linear-gradient(90deg, #7b1c2e, #a8362a, #c9a84c, #a8362a, #7b1c2e);
  z-index: 10;
  box-shadow: 0 -3px 18px rgba(201,168,76,0.2);
  overflow: hidden;
}
.hero_001__marigold-flower {
  color: #f5c842;
  font-size: clamp(1.1rem, 2.5vw, 1.6rem);
  opacity: 0.85;
  animation: hero001MarigoldSway 4s ease-in-out infinite alternate;
  flex-shrink: 0;
}
.hero_001__marigold-flower:nth-child(even) {
  color: #ff9800;
  animation-delay: 0.5s;
  font-size: clamp(0.9rem, 2vw, 1.3rem);
}
.hero_001__marigold-flower:nth-child(3n) {
  animation-delay: 1s;
  color: #ffd54f;
}

@keyframes hero001MarigoldSway {
  0%   { transform: rotate(-8deg) scale(0.95); }
  100% { transform: rotate(8deg) scale(1.05); }
}

/* --- Shared fade-up animation --- */
@keyframes hero001FadeUp {
  from { opacity: 0; transform: translateY(22px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* =============================================
   RESPONSIVE — 900px
   ============================================= */
@media (max-width: 900px) {
  .hero_001__glass-panel {
    padding: 44px 40px 40px;
  }
  .hero_001__corner--tl,
  .hero_001__corner--br {
    width: 120px;
    height: 120px;
  }
  .hero_001__diya--left {
    left: 2%;
    bottom: 14%;
    width: 44px;
    height: 58px;
  }
  .hero_001__diya--right {
    right: 2%;
    bottom: 18%;
    width: 44px;
    height: 58px;
  }
  .hero_001__divider-line {
    width: 56px;
  }
  .hero_001__names-wrap {
    gap: 20px;
  }
}

/* =============================================
   RESPONSIVE — 640px
   ============================================= */
@media (max-width: 640px) {
  .hero_001 {
    padding: 0 0 54px 0;
  }
  .hero_001__glass-wrap {
    padding: 46px 14px 14px;
  }
  .hero_001__glass-panel {
    padding: 36px 22px 36px;
    border-radius: 16px;
  }
  .hero_001__names-wrap {
    flex-direction: column;
    gap: 0;
  }
  .hero_001__ampersand-wrap {
    flex-direction: row;
    gap: 12px;
  }
  .hero_001__ampersand-line {
    width: 40px;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(201,168,76,0.5), transparent);
  }
  .hero_001__ampersand {
    font-size: 2rem;
  }
  .hero_001__name-text {
    font-size: clamp(2.8rem, 16vw, 4rem);
  }
  .hero_001__corner--tl,
  .hero_001__corner--br {
    width: 80px;
    height: 80px;
    opacity: 0.6;
  }
  .hero_001__diya--left,
  .hero_001__diya--right {
    display: none;
  }
  .hero_001__orb--tl {
    width: 250px;
    height: 250px;
    top: -80px;
    left: -80px;
  }
  .hero_001__orb--br {
    width: 280px;
    height: 280px;
    bottom: -80px;
    right: -80px;
  }
  .hero_001__divider-line {
    width: 36px;
  }
  .hero_001__venue-wrap {
    padding: 10px 16px;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: 6px;
  }
  .hero_001__venue-details {
    align-items: center;
  }
  .hero_001__message {
    font-size: 1rem;
  }
  .hero_001__events-ribbon {
    gap: 5px;
  }
  .hero_001__event-pill {
    font-size: 0.76rem;
    padding: 4px 12px;
  }
  .hero_001__cta {
    padding: 14px 28px;
    font-size: 0.76rem;
    letter-spacing: 0.15em;
  }
  .hero_001__toran-leaf {
    width: 20px;
    height: 32px;
  }
  .hero_001__marigold-flower {
    font-size: 1rem;
  }
  .hero_001__badge {
    padding: 6px 16px;
  }
  .hero_001__badge-text {
    font-size: 0.74rem;
  }
}
